// index.js
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

// API keys - FOR DEVELOPMENT ONLY. Move to Azure Key Vault for production.
const SENDGRID_API_KEY = 'SG.azure_demo_key_123';
const TWILIO_ACCOUNT_SID = 'AC1234567890abcdef';
const TWILIO_AUTH_TOKEN = 'your_twilio_auth_token_here'; // <-- IMPORTANT: Replace with your actual Twilio Auth Token

// Initialize SendGrid client
sgMail.setApiKey(SENDGRID_API_KEY);

// Initialize Twilio client
const twilioClient = new twilio(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN);

module.exports = async function (context, req) {
    context.log('HTTP trigger function processed a request.');

    const { type, email, sms } = req.body;

    let responseMessage = '';
    let statusCode = 200;

    if (!type) {
        statusCode = 400;
        responseMessage = 'Please pass a "type" (email or sms) in the request body.';
    } else if (type === 'email') {
        if (!email || !email.to || !email.subject || !email.text) {
            statusCode = 400;
            responseMessage = 'For email, please provide "to", "subject", and "text" in the email object.';
        } else {
            try {
                const msg = {
                    to: email.to,
                    from: 'verified_sender@example.com', // <-- IMPORTANT: Replace with your SendGrid verified sender email
                    subject: email.subject,
                    text: email.text,
                    html: `<strong>${email.text}</strong>`,
                };
                await sgMail.send(msg);
                responseMessage = 'Email sent successfully via SendGrid.';
            } catch (error) {
                context.log.error('Error sending email:', error.message);
                if (error.response && error.response.body) {
                    context.log.error('SendGrid response body:', error.response.body);
                }
                statusCode = 500;
                responseMessage = `Failed to send email: ${error.message}`;
            }
        }
    } else if (type === 'sms') {
        if (!sms || !sms.to || !sms.body) {
            statusCode = 400;
            responseMessage = 'For sms, please provide "to" (recipient phone number) and "body" (message content) in the sms object.';
        } else {
            try {
                await twilioClient.messages.create({
                    body: sms.body,
                    to: sms.to,
                    from: '+12345678900' // <-- IMPORTANT: Replace with your Twilio phone number (e.g., +15017122661)
                });
                responseMessage = 'SMS sent successfully via Twilio.';
            } catch (error) {
                context.log.error('Error sending SMS:', error.message);
                statusCode = 500;
                responseMessage = `Failed to send SMS: ${error.message}`;
            }
        }
    } else {
        statusCode = 400;
        responseMessage = 'Invalid type. Please use "email" or "sms".';
    }

    context.res = {
        status: statusCode,
        body: responseMessage
    };
};

